import https from 'https';
import { axiosRequest } from '../util';
import type { FixedParameters, FixedFacets } from '../types/query';
import type { Response } from '../types/FBresponse';
import type { MatrixConfigJSON } from '../types/configJSON';

type Facets = { [key: string]: string | string[] };
type Parameters = { [key: string]: string };

function baseURL(site: string | undefined): string {
    switch (site) {
        case 'citysport':
            return 'https://www.citysport.org.uk/web-services/fb/';
        case 'city':
            return 'https://www.citystgeorges.ac.uk/web-services/dxp-fb';
        case 'bayes':
            return 'https://www.bayes.citystgeorges.ac.uk/webservices';
        default:
            return 'https://www.citystgeorges.ac.uk/web-services/dxp-fb';
    }
}

function dxpFindRootURL(site: string | undefined): string {
    switch (site) {
        case 'citysport':
            return '/funnelback-dxp-find-test/';
        case 'city':
            return '/funnelback-dxp-find-test/_nocache';
        case 'bayes':
            return '/funnelback-find-dxp-json';
        default:
            return '/dxp-fb';
    }
}

const dxpSuggestRootUrl = '/funnelback-dxp-suggest',
    maximumSuggestions = 100,
    timeout = 30000;

/**
 * Funnelback search query.
 *
 * @param {string} collection The Funnelback collection to query.
 * @param {string} [query] The query string.
 * @param {string} [sortType] The field to sort by.
 * @param {integer} startRank The first result to return.
 * @param {integer} numRank The number of results to return.
 * @param {object} [facets] A map of facets to query strings.
 * @return {Promise} - A promise of search results.
 */
export function find(
    collection: string,
    fixedFacets: FixedFacets[] | undefined,
    fixedParameters: FixedParameters[] | undefined,
    query: string,
    sortType: string | undefined,
    startRank: number | undefined,
    numRank: number | undefined,
    facets: Facets,
    parameters: Parameters | undefined,
    site: string | undefined,
    facetLabels: MatrixConfigJSON['facetLabels'] | undefined,
    profile?: string
): [Promise<Response>, AbortController] {
    const fixedParams: { [key: string]: string } = {};
    if (fixedParameters) {
        fixedParameters.forEach((param) => {
            fixedParams[`${param.name}`] = param.value;
        });
    }

    const params: { [key: string]: string } = {},
        paramsKeys = parameters ? Object.keys(parameters) : [];

    if (parameters) {
        paramsKeys.forEach((key: string) => (params[key] = parameters[key]));
    }

    const fixedFacetParams: { [key: string]: string } = {};
    if (fixedFacets) {
        fixedFacets.forEach((facet) => {
            fixedFacetParams[`meta_${facet.meta}_sand`] = facet.value;
        });
    }

    const facetParams: { [key: string]: string | string[] } = {},
        facetKeys = Object.keys(facets),
        facetValues = Object.values(facets);

    facetValues.forEach((value, i) => {
        if (Array.isArray(value)) {
            const facetName =
                facetLabels?.find((label) => label.meta === facetKeys[i])
                    ?.facetName || facetKeys[i];
            return (facetParams[`f±${facetName}|${facetKeys[i]}`] = value);
        } else {
            return (facetParams[`meta_${facetKeys[i]}_sand`] =
                facets[facetKeys[i]]);
        }
    });

    const controller = new AbortController(),
        call = controller.signal,
        config = {
            baseURL: baseURL(site),
            signal: call,
            httpsAgent: new https.Agent({ keepAlive: true }),
            url: dxpFindRootURL(site),
            timeout: timeout,
            params: {
                ...fixedParams,
                ...fixedFacetParams,
                ...facetParams,
                ...params,
                collection: collection,
                profile: profile || '_default',
                num_ranks: numRank,
                query: query,
                sort: sortType || '',
                start_rank: startRank,
            },
        };

    const defaultResponse: Response = {
        bestBets: [],
        results: [],
        summary: {
            totalMatching: 0,
            numRanks: 0,
            currStart: 1,
        },
        facets: [],
        // Add other required fields if your Response type has them
    };

    return [
        axiosRequest<Response>(config).then((data) => data || defaultResponse),
        controller,
    ];
}

/**
 * Funnelback suggestion query.
 *
 * @param {string} collection The Funnelback collection to query.
 * @param {string} partialQuery The string to make suggestions for.
 * @return {Promise} - A promise of an array of suggestion strings.
 */
export function suggest(
    collection: string,
    partialQuery: string,
    site: string | undefined
): [Promise<string[]>, AbortController] {
    const controller = new AbortController(),
        call = controller.signal,
        config = {
            baseURL: baseURL(site),
            signal: call,
            url: dxpSuggestRootUrl,
            timeout: timeout,
            params: {
                collection: collection,
                partial_query: partialQuery,
                show: maximumSuggestions,
            },
        };

    return [
        axiosRequest<string[]>(config).then((data) => data || []),
        controller,
    ];
}

/**
 * Finder configuration.
 *
 * @param {string} url The Finder configuration file.
 * @return {Promise} - A promise of  configuration object.
 */
export function finderConfig(url: string) {
    const config = {
        timeout: timeout,
        url: url,
    };

    return axiosRequest(config);
}
